int pr_inet_resetlisten(pool *p, conn_t *c) {
  if (c == NULL) {
    errno = EINVAL;
    return -1;
  }

  c->mode = CM_LISTEN;
  if (pr_inet_set_block(c->pool, c) < 0) {
    c->xerrno = errno;
    return -1;
  }

  return 0;
}

